#include <stdio.h>

int add(int a, int b) { return a + b; }
int subtract(int a, int b) { return a - b; }
int multiply(int a, int b) { return a * b; }

int compute(int (*op)(int, int), int x, int y) {
  return op(x, y);
}

int main() {
  int (*funcPtr)(int, int);
  funcPtr = add;
  printf("Add: %d\n", funcPtr(10, 5));
  printf("Using compute: %d\n", compute(multiply, 6, 7));
  int (*ops[])(int, int) = {add, subtract, multiply};
  for (int i = 0; i < 3; i++) {
    printf("%d ", ops[i](10, 3));
  }
  printf("\n");
  return 0;
}
